import Combine
import Foundation

class URLFetcher {
    static let shared = URLFetcher()

    func fetchData(from url: URL) -> AnyPublisher<Data, Error> {
        URLSession.shared.dataTask(with: url) 
            .publisher
            .map { $0.data } 
            .eraseToAnyPublisher()
    }
}

func processData(data: Data) {
    // Xử lý dữ liệu ở đây
    print("Received data: \(data.count) bytes")
}

func fetchDataAndProcess(url: URL) {
    URLFetcher.shared.fetchData(from: url)
        .sink(receiveCompletion: { completion in
            switch completion {
            case .finished: print("Finished fetching data")
            case .failure(let error): print("Error fetching data: \(error)")
            }
        }, receiveValue: { data in
            processData(data: data)
        })
        .store(in: &cancellables)
}

var cancellables = Set<AnyCancellable>()

// Ví dụ sử dụng
let url = URL(string: "https://www.example.com")!
fetchDataAndProcess(url: url)
```
Giải thích: `URLFetcher` chứa hàm `fetchData` sử dụng `URLSession` để tải dữ liệu từ URL.  `.publisher` chuyển đổi `URLSession` task thành một publisher.  `map` trích xuất dữ liệu từ response.  `sink` subscribe vào publisher và xử lý dữ liệu hoặc lỗi. `eraseToAnyPublisher()` ẩn chi tiết implementation của publisher.

