import StoreKit

class ProductManager: ObservableObject {
    @Published var products: [Product] = []
    let productIDs = ["com.example.premiumfeature"]

    init() {
        fetchProducts()
    }

    func fetchProducts() {
        let request = Product.request(for: productIDs)
        request.onCompletion = { result in
            DispatchQueue.main.async {
                switch result {
                case .success(let products): self.products = products
                case .failure(let error): print("Error fetching products: \(error)")
                }
            }
        }
    }

    func purchaseProduct(product: Product) {
        if Product.canMakePayments() {
            let transaction = Transaction(product: product)
            transaction.onCompletion = { result in
                DispatchQueue.main.async {
                    switch result {
                    case .success: print("Purchase successful!")
                    case .failure(let error): print("Purchase failed: \(error)")
                    }
                }
            }
            transaction.start()
        } else {
            print("User cannot make purchases.")
        }
    }
}
```
Giải thích: `ProductManager` quản lý in-app purchases.  `fetchProducts` sử dụng `Product.request(for:)` để lấy thông tin sản phẩm.  `purchaseProduct` sử dụng `Transaction` để bắt đầu purchase.  `Product.canMakePayments()` kiểm tra xem người dùng có thể thực hiện purchase hay không.  Quan trọng: Cấu hình App Store Connect và tạo product ID chính xác.

